import { Marker } from '@vis.gl/react-maplibre';
import { useMemo, useRef, type PropsWithChildren } from 'react';

import { TooltipContext } from '../contexts/tooltip.context.js';
import {
  useMapTooltipHoveredLayerIdState,
  useMapTooltipLocationState,
} from '../store/selectors.js';

export const TooltipWrapper = (
  props: PropsWithChildren<{ layerId: string }>,
) => {
  const markerRef = useRef<maplibregl.Marker>(null);
  const value = useMemo(() => ({ markerRef }), []);
  const hoveredLayeredId = useMapTooltipHoveredLayerIdState();
  const { children, layerId } = props;

  const { lat, lng } = useMapTooltipLocationState() || {};

  if (hoveredLayeredId !== layerId || !lat || !lng) {
    return null;
  }

  return (
    <>
      <Marker latitude={lat} longitude={lng} ref={markerRef} opacity="0">
        <span></span>
      </Marker>
      <TooltipContext.Provider value={value}>
        {children}
      </TooltipContext.Provider>
    </>
  );
};
